CREATE OR REPLACE FUNCTION f_gap_fill_update(tbl text, id text, row_num text)
RETURNS void
LANGUAGE plpgsql AS
$func$
DECLARE
    cols text[];
    col text;
    update_sets text := '';
    ff_columns text := '';
BEGIN
    -- Get all nullable columns except the id and row_num columns
    SELECT array_agg(column_name::text)
    INTO cols
    FROM information_schema.columns c
    WHERE c.table_name = tbl
      AND c.is_nullable = 'YES'
      AND c.column_name NOT IN (id, row_num);

    IF cols IS NULL THEN
        RETURN;
    END IF;

    -- Build the forward-fill select expressions and update set clauses
    FOREACH col IN ARRAY cols
    LOOP
        ff_columns := ff_columns || format(
            ', COALESCE(%I, LAG(%I) OVER (PARTITION BY %I ORDER BY %I)) AS %I',
            col, col, id, row_num, col
        );
        IF update_sets <> '' THEN
            update_sets := update_sets || ', ';
        END IF;
        update_sets := update_sets || format('%I = sub.%I', col, col);
    END LOOP;

    -- Perform the update using a subquery with forward fill applied
    -- Using a recursive approach: repeat until no more nulls are filled
    LOOP
        EXECUTE format(
            'UPDATE %I AS t SET %s FROM (
                SELECT %I, %I %s
                FROM %I
                WINDOW w AS (PARTITION BY %I ORDER BY %I)
            ) AS sub
            WHERE t.%I = sub.%I AND t.%I = sub.%I',
            tbl, update_sets,
            id, row_num, ff_columns,
            tbl,
            id, row_num,
            id, id, row_num, row_num
        );

        -- Check if there are still NULLs that can be filled
        -- If no rows were updated in a meaningful way, exit
        IF NOT FOUND THEN
            EXIT;
        END IF;

        -- Check if any nullable column still has NULLs that could be forward-filled
        DECLARE
            has_nulls boolean := false;
            check_sql text := 'SELECT EXISTS (SELECT 1 FROM ' || quote_ident(tbl) || ' a WHERE ';
            conditions text := '';
        BEGIN
            FOREACH col IN ARRAY cols
            LOOP
                IF conditions <> '' THEN
                    conditions := conditions || ' OR ';
                END IF;
                conditions := conditions || format(
                    '(%I IS NULL AND LAG(%I) OVER (PARTITION BY %I ORDER BY %I) IS NOT NULL)',
                    col, col, id, row_num
                );
            END LOOP;
            EXECUTE 'SELECT EXISTS (SELECT 1 FROM (SELECT *, ' ||
                array_to_string(
                    ARRAY(SELECT format('CASE WHEN %I IS NULL AND LAG(%I) OVER (PARTITION BY %I ORDER BY %I) IS NOT NULL THEN 1 ELSE 0 END AS chk_%s', c, c, id, row_num, c) FROM unnest(cols) AS c),
                    ', '
                ) || ' FROM ' || quote_ident(tbl) || ') x WHERE ' ||
                array_to_string(
                    ARRAY(SELECT format('chk_%s = 1', c) FROM unnest(cols) AS c),
                    ' OR '
                ) || ')'
            INTO has_nulls;

            IF NOT has_nulls THEN
                EXIT;
            END IF;
        END;
    END LOOP;
END
$func$

CREATE OR REPLACE FUNCTION pg_try_advisory_lock_with_timeout(key bigint)
RETURNS boolean AS $$
BEGIN
    -- Set a local lock timeout of 1 second (only affects this transaction)
    PERFORM set_config('lock_timeout', '1s', true);

    -- Attempt to acquire the advisory lock (transaction-level)
    PERFORM pg_advisory_xact_lock(key);

    -- If we reach here, the lock was acquired successfully
    RETURN true;

EXCEPTION
    WHEN lock_not_available THEN
        -- Lock could not be acquired within the timeout
        RETURN false;
    WHEN deadlock_detected THEN
        -- Deadlock was detected
        RETURN false;
END;
$$ LANGUAGE plpgsql

DROP AGGREGATE IF EXISTS GapFill(anyelement);
DROP FUNCTION IF EXISTS GapFillInternal(anyelement, anyelement);

CREATE OR REPLACE FUNCTION GapFillInternal(s anyelement, v anyelement) RETURNS anyelement AS $$
DECLARE
    temp alias for $0;
BEGIN
    IF v IS NULL AND s IS NOT NULL THEN
        temp := s;
    ELSIF s IS NULL AND v IS NOT NULL THEN
        temp := v;
    ELSIF s IS NOT NULL AND v IS NOT NULL THEN
        temp := v;
    ELSE
        temp := NULL;
    END IF;
    RETURN temp;
END;
$$ LANGUAGE PLPGSQL;

CREATE AGGREGATE GapFill(anyelement) (
    SFUNC = GapFillInternal,
    STYPE = anyelement
);

