DROP PROCEDURE IF EXISTS delete_excess_common_cards;

DELIMITER //

CREATE PROCEDURE delete_excess_common_cards()
BEGIN
    DECLARE card_count INT;
    DECLARE excess_count INT;

    SELECT COUNT(*) INTO card_count FROM cards WHERE rarity = 'common';

    IF card_count > 100 THEN
        SET excess_count = card_count - 100;
        SET @sql = CONCAT('DELETE FROM cards WHERE rarity = ''common'' ORDER BY id LIMIT ', excess_count);
        PREPARE stmt FROM @sql;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;
    END IF;
END //

DELIMITER ;

DROP EVENT IF EXISTS delete_extra_common_cards;

CREATE EVENT delete_extra_common_cards
ON SCHEDULE EVERY 1 MONTH
DO
    CALL delete_excess_common_cards()

DROP PROCEDURE IF EXISTS drop_empty_columns;

CREATE PROCEDURE drop_empty_columns()
BEGIN
    DECLARE done INT DEFAULT 0;
    DECLARE col_name VARCHAR(255);
    DECLARE cnt INT;

    DECLARE col_cursor CURSOR FOR
        SELECT COLUMN_NAME
        FROM INFORMATION_SCHEMA.COLUMNS
        WHERE TABLE_SCHEMA = DATABASE()
          AND TABLE_NAME = 'digital_localization_analysis';

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

    OPEN col_cursor;

    read_loop: LOOP
        FETCH col_cursor INTO col_name;
        IF done THEN
            LEAVE read_loop;
        END IF;

        SET @check_sql = CONCAT(
            'SELECT COUNT(`', col_name, '`) INTO @cnt FROM `digital_localization_analysis` WHERE `', col_name, '` IS NOT NULL'
        );
        PREPARE stmt FROM @check_sql;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;

        IF @cnt = 0 THEN
            SET @drop_sql = CONCAT(
                'ALTER TABLE `digital_localization_analysis` DROP COLUMN `', col_name, '`'
            );
            PREPARE stmt2 FROM @drop_sql;
            EXECUTE stmt2;
            DEALLOCATE PREPARE stmt2;
        END IF;
    END LOOP;

    CLOSE col_cursor;
END;

CALL drop_empty_columns();

